/**
 * DHARMA COMMAND — Route Truth Map.
 *
 * Every dashboard route annotated with the actual truth status of its
 * backend data source(s).  Generated by probing the FastAPI backend on
 * 2026-04-04.
 *
 * Statuses:
 *   live        — endpoint exists AND returns real data
 *   partial     — endpoint exists but returns empty/null (needs data seeding)
 *   decorative  — page renders static/hardcoded UI with no backend call
 *   broken      — endpoint returns 404, 500, or "unable to open database file"
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type TruthStatus = "live" | "partial" | "decorative" | "broken";

export interface EndpointTruth {
  /** API path probed. */
  path: string;
  /** HTTP method. */
  method: "GET" | "POST" | "PATCH" | "DELETE";
  /** HTTP status returned during probe. */
  httpStatus: number;
  /** Truth classification. */
  truth: TruthStatus;
  /** Short note on what we observed. */
  note: string;
}

export interface RouteTruth {
  /** Dashboard route path (e.g. "/dashboard/agents"). */
  route: string;
  /** Overall truth for the page — the *worst* endpoint it depends on. */
  truth: TruthStatus;
  /** All endpoints the page depends on. */
  endpoints: EndpointTruth[];
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function worstTruth(statuses: TruthStatus[]): TruthStatus {
  if (statuses.includes("broken")) return "broken";
  if (statuses.includes("decorative")) return "decorative";
  if (statuses.includes("partial")) return "partial";
  return "live";
}

