// ---------------------------------------------------------------------------
// Lookup helpers
// ---------------------------------------------------------------------------

const _byRoute = new Map(ROUTE_TRUTH.map((r) => [r.route, r]));

/** Get truth for a specific dashboard route. */
export function getRouteTruth(route: string): RouteTruth | undefined {
  return _byRoute.get(route);
}

/** Get all routes matching a truth status. */
export function routesByTruth(status: TruthStatus): RouteTruth[] {
  return ROUTE_TRUTH.filter((r) => r.truth === status);
}

/** Summary counts for quick display. */
export function truthSummary(): Record<TruthStatus, number> {
  const counts: Record<TruthStatus, number> = {
    live: 0,
    partial: 0,
    decorative: 0,
    broken: 0,
  };
  for (const r of ROUTE_TRUTH) {
    counts[r.truth]++;
  }
  return counts;
}
